+    fn record_pending_liveness_feedback(
+        &mut self,
+        agent: &str,
+        action: LivenessAction,
+        expected_loss: f64,
+        issued_at_micros: i64,
+    ) {
+        if action == LivenessAction::DeclareAlive {
+            return;
+        }
+        self.pending_liveness_feedback.insert(
+            agent.to_string(),
